import{_ as a,c as s,o as n,ae as p}from"./chunks/framework.Ck3L_38O.js";const g=JSON.parse('{"title":"6.S081 Lab1","description":"","frontmatter":{"title":"6.S081 Lab1"},"headers":[],"relativePath":"course/6.S081/Lab1.md","filePath":"course/6.S081/Lab1.md"}'),o={name:"course/6.S081/Lab1.md"};function i(l,e,t,c,d,r){return n(),s("div",null,[...e[0]||(e[0]=[p(`<h1 id="xv6-and-unix-utilities" tabindex="-1">Xv6 and Unix utilities <a class="header-anchor" href="#xv6-and-unix-utilities" aria-label="Permalink to &quot;Xv6 and Unix utilities&quot;">​</a></h1><h2 id="boot-xv6-easy" tabindex="-1">Boot xv6 (easy) <a class="header-anchor" href="#boot-xv6-easy" aria-label="Permalink to &quot;Boot xv6 (easy)&quot;">​</a></h2><p>使用 Ubuntu 20.04 ，安装需要的工具</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt-get install git build-essential gdb-multiarch qemu-system-misc gcc-riscv64-linux-gnu binutils-riscv64-linux-gnu</span></span></code></pre></div><p>部署 xv6</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone git://g.csail.mit.edu/xv6-labs-2021</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>cd xv6-labs-2021</span></span>
<span class="line"><span>git checkout util</span></span></code></pre></div><p>这里使用 <code>ls</code> 就可以看到 xv6 的源码了。<br> 接下来执行 <code>make qemu</code> 就会编译运行 xv6 了。</p><p>使用 <code>Ctrl-a x</code> 就可以退出 xv6 （按住 Ctrl 按下 a ，松开 Ctrl 和 a ，按下 x）。</p><h2 id="sleep-easy" tabindex="-1">sleep (easy) <a class="header-anchor" href="#sleep-easy" aria-label="Permalink to &quot;sleep (easy)&quot;">​</a></h2><p>实现一个 sleep 接口。</p><p><strong>实验思路</strong></p><ol><li>参考 <em>user</em> 下的其他程序，将头文件引入，(<em>kernel/types.h</em> 声明类型的头文件， <em>user/user.h</em> 声明系统第哦啊用的头文件，<em>ulib.c</em> 声明工具的头文件)</li><li>写 <code>int main(int argc, char* argv[])</code> 函数。其中，参数 <code>argc</code> 是所有参数的个数，<code>argv[]</code> 是参数的内容，第 0 个参数是程序的全名，其他的是用户输入的其他参数</li><li>先判断用户输入的参数是否正确，只要参数不等于 2 个，就知道用户输入的参数是有错误的，就可以打印返回错误信息。参考 <em>user/echo.c</em> ，可以使用 <code>fprintf()</code> 函数打印错误信息，最后需要调用 <code>exit(1)</code>，0 表示正常，1 表示异常。</li><li>剩下的就是参数没有问题的情况，由于接收的是字符类型，所以应该先用 <code>atoi()</code> 函数将字符转换为整数，调用系统调用 <code>sleep()</code> 函数，最后调用系统调用 <code>exit(0)</code> 退出</li><li>在 <em>Makefile</em> 中添加配置，在 <code>UPROGS</code> 的最后一行添加 <code>$U/_sleep\\</code></li></ol><h2 id="pingpong-easy" tabindex="-1">pingpong (easy) <a class="header-anchor" href="#pingpong-easy" aria-label="Permalink to &quot;pingpong (easy)&quot;">​</a></h2><p>实现一个 pingpong 接口。</p><p><strong>实验思路</strong></p><ol><li>按照实验目的的思路，先使用 <code>pipe</code> 来创建管道，由于管道是半双工的，因此需要创建两个管道，一个是父进程向子进程发送字节，一个是子进程向父进程发送字节，其中 p[0] 是读端， p[1] 是写端</li><li>通过 <code>fork</code> 建立子进程，通过阅读 xv6文档可知，对于父进程， <code>fork</code> 会返回父进程的 pid ，同时创建并返回一个 pid 是 0 子进程；让父进程通过管道发送 &quot;ping&quot; 给子进程，然后使用 <code>read</code> 开始读取来自子进程的 <code>pong</code></li><li>当子进程使用 <code>read</code> 读取管道，读取到父进程发送的 &quot;ping&quot; 时，通过 <code>getpid</code> 获取 &quot;pid&quot; ，然后打印出 &quot;&lt;pid&gt;: received ping&quot; ，之后使用 <code>write</code> 发送 &quot;pong&quot; 给父进程，最后退出子进程</li><li>当父进程读取到子进程的发送的 <code>pong</code> 时，打印出 &quot;&lt;pid&gt;: received pong&quot;</li></ol><h2 id="primes-moderate-hard" tabindex="-1">primes (moderate)/(hard) <a class="header-anchor" href="#primes-moderate-hard" aria-label="Permalink to &quot;primes (moderate)/(hard)&quot;">​</a></h2><p>实现一个多进程并发打印素数的接口。</p><p><strong>实验思路</strong></p><ol><li>首先看链接中的图，可以看出，数字全部输入到第一条管道，然后打印出 2 ，然后将所有 2 的倍数都剔除，接着把被剔除的数字全部输入到下一条管道，第二个进程打印的管道传输来的第一个数字 3 ，然后将所有 3 的倍数剔除，以此类推</li><li>看图片上面的伪代码，首先 p 从左边的管道获取到一个数字，打印 p ，循环，n 从左边的的管道获取一个数字，如果 p 不能整除 n ，则将 n 发送到右边的管道</li><li>代码思路，<code>main</code> 函数中，使用 <code>fork</code> 生成父子进程，使用子进程调用一个 <code>primes</code> 函数，父进程利用管道将数字传输给子进程，子进程将读管道传输给 <code>primes</code> 函数</li><li><code>primes</code> 函数打印当前数字，生成一个用于父子传递的管道，对应提示网站的右边的传输，然后再使用 <code>fork()</code> 生成父子进程，然后子进程递归调用 <code>primes</code>函数，父进程接口读取参数中传来的数据，筛选完后发送给子进程</li></ol><p><strong>踩到的坑</strong></p><ul><li>一定一定一定要记得把不需要还有用完的文件描述符关掉 <blockquote><p>对于管道读操作，如果没有数据写入，会出现<strong>阻塞</strong>，直到有数据写入<br> 对于管道读操作，如果所有写端被关闭时，<code>read()</code> 会返回 <code>0</code> (EOF)<br> 对于管道写操作，缓冲区满的时候，会出现<strong>阻塞</strong>，直到有空间写入<br> 对于管道写操作，如果所有读端被关闭时，会触发 <code>SIGPIPE</code> 信号（默认中止进程）</p></blockquote></li></ul><h2 id="find-moderate" tabindex="-1">find (moderate) <a class="header-anchor" href="#find-moderate" aria-label="Permalink to &quot;find (moderate)&quot;">​</a></h2><p>写一个简单的版本的 UNIX 的查找程序：找到目录中所有带特定名称的文件。</p><p><strong>实验思路</strong></p><ol><li>根据提示，先看一下 <em>user/ls.c</em> 是如何读取目录的，使用 <code>open()</code> 打开路径会返回一个文件描述符，使用 <code>fstat()</code> 获取路径信息；然后读取路径类型，如果路径是文件，直接打印，如果是文件夹，判断一下路径是否太长，太长直接返回错误，否则循环读取，每次读一个文件或文件夹，如果文件夹的 <em>inodenum</em> 是 0 ，说明这个文件失效了，直接跳过，接着将文件名复制到路径后面，再在路径末尾新增一个空字符串，最后格式化打印</li><li>先遍历当前目录的所有文件，查找出文件名带有目标字符的文件，如果找到直接打印，如果找到文件夹，就递归查找</li></ol><h2 id="xargs-moderate" tabindex="-1">xargs (moderate) <a class="header-anchor" href="#xargs-moderate" aria-label="Permalink to &quot;xargs (moderate)&quot;">​</a></h2><p>写一个简单版本的 UNIX 的 <em>xargs</em> 程序：从标准输入中读取行数，并为每一行运行一条命令，同时将行数作为参数提供给命令</p><p><strong>实验思路</strong></p><ol><li>进行参数校验，如果大于 <code>MAXARG</code> ，直接返回错误</li><li>通过 <code>read()</code> 读取文件描述 <em>0</em> ，可以读取到管道传递的数据。系统调用循环读取输入，直到遇到 <em>EOF(文件结束符)</em> ，需要开辟新的内存来存储读取到的参数，同时将所有的参数存储到一个指针数组中，但是不可以使用 <code>main()</code> 里的 <code>argv[]</code> ，因为容量不是固定的</li><li>最后，使用 <code>fork()</code> ，创建一个子进程，在子进程中调用 <code>exec()</code> ，父进程一定要使用 <code>wait()</code> 等待子进程执行结束再退出</li></ol><p><strong>扩展</strong><br> 至于为什么要使用子进程，我也很好奇，问了一下 ds ，原因如下</p><blockquote><p>防止某个命令会修改环境变量，导致后续的操作逻辑出错<br> 如果不使用子进程，不能实现<strong>并行执行</strong><br> 如果有多命令时，单个命令出错会导出整个 <em>xargs</em> 程序崩溃</p></blockquote><p><strong>踩到的坑</strong></p><ul><li>头文件顺序对编译会有影响，<code>user/user.h</code> 不能第一个引入，否则会编译出错</li></ul><hr><h2 id="lab1-所有实现测试" tabindex="-1">Lab1 所有实现测试 <a class="header-anchor" href="#lab1-所有实现测试" aria-label="Permalink to &quot;Lab1 所有实现测试&quot;">​</a></h2><p>执行 <code>make grade</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>== Test sleep, no arguments == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>sleep, no arguments: OK (2.8s) </span></span>
<span class="line"><span>== Test sleep, returns == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>sleep, returns: OK (0.7s) </span></span>
<span class="line"><span>== Test sleep, makes syscall == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>sleep, makes syscall: OK (1.0s) </span></span>
<span class="line"><span>== Test pingpong == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>pingpong: OK (1.0s) </span></span>
<span class="line"><span>== Test primes == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>primes: OK (0.9s) </span></span>
<span class="line"><span>== Test find, in current directory == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>find, in current directory: OK (1.0s) </span></span>
<span class="line"><span>== Test find, recursive == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>find, recursive: OK (1.2s) </span></span>
<span class="line"><span>== Test xargs == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>xargs: OK (1.1s) </span></span>
<span class="line"><span>== Test time == </span></span>
<span class="line"><span>time: FAIL </span></span>
<span class="line"><span>    Cannot read time.txt</span></span>
<span class="line"><span>Score: 99/100</span></span>
<span class="line"><span>make: *** [Makefile:237: grade] Error 1</span></span></code></pre></div><p>最后一个出错了，搜索了一下<a href="https://www.cnblogs.com/duile/p/15981486.html" target="_blank" rel="noreferrer">参考链接</a>，只需要在 xv6-labs-2020 的目录下新建一个 <strong>time.txt</strong> 文件，然后在里面输入一个整数就可以了。应该是 mit 的老师用来了解学生的进度的</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>== Test xargs == </span></span>
<span class="line"><span>$ make qemu-gdb</span></span>
<span class="line"><span>xargs: OK (1.2s) </span></span>
<span class="line"><span>== Test time == </span></span>
<span class="line"><span>time: OK </span></span>
<span class="line"><span>Score: 100/100</span></span></code></pre></div>`,40)])])}const u=a(o,[["render",i]]);export{g as __pageData,u as default};
